def probability_operations(p_a, p_b, p_a_and_b):
    # Calculate union probability
    p_a_or_b = p_a + p_b - p_a_and_b

    # Calculate conditional probability P(A|B)
    if p_b > 0:
        p_a_given_b = p_a_and_b / p_b
    else:
        p_a_given_b = None

    # Check independence
    is_independent = (p_a_and_b == p_a * p_b)

    return {
        'P(A ∪ B)': p_a_or_b,
        'P(A | B)': p_a_given_b,
        'Independent': is_independent
    }

# Example: P(A)=0.4, P(B)=0.5, P(A∩B)=0.2
result = probability_operations(0.4, 0.5, 0.2)
print(result)  # {'P(A ∪ B)': 0.7, 'P(A | B)': 0.4, 'Independent': True}

FUNCTION BayesTheorem(priorA, likelihoodBA, evidenceB)
BEGIN
  // priorA: P(A) - initial belief
  // likelihoodBA: P(B|A) - probability of evidence given A
  // evidenceB: P(B) - probability of evidence

  posterior <- (likelihoodBA * priorA) / evidenceB
  RETURN posterior
END FUNCTION

// Example: Medical diagnosis
// P(Disease) = 0.01, P(Positive|Disease) = 0.95, P(Positive) = 0.108
// P(Disease|Positive) = ?

priorD <- 0.01
likelihood <- 0.95  // P(Positive|Disease)
evidence <- 0.108  // P(Positive)

result <- BayesTheorem(priorD, likelihood, evidence)
OUTPUT "Probability of disease given positive test:", result

public class EventProperties {
    public static void main(String[] args) {
        double pA = 0.4, pB = 0.5, pAandB = 0.2;

        // Check mutual exclusivity
        boolean mutuallyExclusive = (pAandB == 0);
        System.out.println("Mutually Exclusive: " + mutuallyExclusive);

        // Check independence
        boolean independent = (pAandB == pA * pB);
        System.out.println("Independent: " + independent);

        // Calculate P(A U B)
        double pAorB = pA + pB - pAandB;
        System.out.println("P(A ∪ B): " + pAorB);

        // Calculate P(A|B)
        double pAgivenB = (pB > 0) ? pAandB / pB : 0;
        System.out.println("P(A|B): " + pAgivenB);
    }
}
// Output:
// Mutually Exclusive: false
// Independent: true
// P(A ∪ B): 0.7
// P(A|B): 0.4
